import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

// ─── Notifications ────────────────────────────────────────────────────────────
const NOTIFICATIONS = [
  { id:1, icon:'❤️', title:'Heart Rate Normal',          desc:'Resting heart rate is 72 bpm — within healthy range.',            time:'2 min ago', type:'good', tag:'Heart'    },
  { id:2, icon:'😴', title:'Sleep Goal Not Met',          desc:'You only slept 5.5 hrs last night. Try to aim for 8 hrs tonight.', time:'1 hr ago',  type:'warn', tag:'Sleep'    },
  { id:3, icon:'🔥', title:'Calorie Goal Almost Reached', desc:"You're at 72% of your daily calorie burn goal. Keep it up!",       time:'3 hr ago',  type:'info', tag:'Calories' },
  { id:4, icon:'🧠', title:'Stress Level Elevated',       desc:'HRV indicates moderate stress today. A short walk may help.',      time:'5 hr ago',  type:'warn', tag:'Stress'   },
  { id:5, icon:'👟', title:'Step Goal Achieved!',         desc:'You hit 9,158 steps today — 91% of your daily goal. Great work!',  time:'6 hr ago',  type:'good', tag:'Steps'    },
];
const NS = {
  good: { dot:'#34d399', glow:'rgba(52,211,153,0.6)',  bg:'rgba(52,211,153,0.07)',  border:'rgba(52,211,153,0.2)',  tag:{color:'#34d399',bg:'rgba(52,211,153,0.12)',border:'rgba(52,211,153,0.25)'} },
  warn: { dot:'#fbbf24', glow:'rgba(251,191,36,0.6)',  bg:'rgba(251,191,36,0.07)',  border:'rgba(251,191,36,0.2)',  tag:{color:'#fbbf24',bg:'rgba(251,191,36,0.12)',border:'rgba(251,191,36,0.25)'} },
  info: { dot:'#60a5fa', glow:'rgba(96,165,250,0.6)',  bg:'rgba(96,165,250,0.07)',  border:'rgba(96,165,250,0.2)',  tag:{color:'#60a5fa',bg:'rgba(96,165,250,0.12)',border:'rgba(96,165,250,0.25)'} },
};

// ─── Devices ──────────────────────────────────────────────────────────────────
const INIT_DEVICES = [
  { id:'apple',   name:'Apple Watch',    img:'/devices/apple-watch.png',   desc:'Series 9 · watchOS 10',      color:'#60a5fa', connected:true  },
  { id:'fitbit',  name:'Fitbit Sense 2', img:'/devices/fitbit.png',        desc:'Firmware 1.187.48',           color:'#34d399', connected:false },
  { id:'samsung', name:'Galaxy Watch 6', img:'/devices/samsung-watch.png', desc:'Wear OS 4 · One UI Watch 6',  color:'#a78bfa', connected:false },
  { id:'whoop',   name:'WHOOP 4.0',      img:'/devices/whoop.png',         desc:'Fitness & Recovery Tracker',  color:'#f87171', connected:false },
];
const NEW_DEVICES = [
  { id:'oura',     name:'Oura Ring Gen 3',   img:'/devices/oura.png',     desc:'Sleep & Recovery Ring',      color:'#fbbf24' },
  { id:'garmin',   name:'Garmin Fenix 7',    img:'/devices/garmin.png',   desc:'GPS Multisport Watch',       color:'#34d399' },
  { id:'polar',    name:'Polar H10',         img:'/devices/polar.png',    desc:'Heart Rate Sensor',          color:'#f87171' },
  { id:'withings', name:'Withings ScanWatch',img:'/devices/withings.png', desc:'Hybrid Smartwatch + ECG',    color:'#60a5fa' },
];

const SHARED_STYLES = `
  @keyframes notifDropIn {
    from { opacity:0; transform:translateY(-10px) scale(0.95); }
    to   { opacity:1; transform:translateY(0) scale(1); }
  }
  @keyframes centrePopIn {
    from { opacity:0; transform:translate(-50%,-48%) scale(0.93); }
    to   { opacity:1; transform:translate(-50%,-50%) scale(1); }
  }
  @keyframes spin { to { transform:rotate(360deg); } }
  .notif-scroll::-webkit-scrollbar,
  .sync-scroll::-webkit-scrollbar  { width:5px; }
  .notif-scroll::-webkit-scrollbar-track,
  .sync-scroll::-webkit-scrollbar-track  { background:transparent; }
  .notif-scroll::-webkit-scrollbar-thumb,
  .sync-scroll::-webkit-scrollbar-thumb  { background:rgba(91,184,255,0.2); border-radius:4px; }
  .notif-scroll::-webkit-scrollbar-thumb:hover,
  .sync-scroll::-webkit-scrollbar-thumb:hover { background:rgba(91,184,255,0.4); }
`;

// ─── Device row helper ────────────────────────────────────────────────────────
const DeviceRow = ({ dev, actionLabel, actionColor, onAction, isSyncing, isConnected }) => (
  <div style={{
    display:'flex', alignItems:'center', gap:'1.1rem',
    padding:'1.05rem 1.2rem', borderRadius:20,
    background: isConnected ? `${dev.color}0f` : 'rgba(255,255,255,0.03)',
    border:`1px solid ${isConnected ? dev.color+'33' : 'rgba(255,255,255,0.07)'}`,
    transition:'all 0.2s',
  }}>
    {/* Icon */}
    <div style={{
      width:52, height:52, borderRadius:16, flexShrink:0,
      background: isConnected ? `${dev.color}22` : 'rgba(255,255,255,0.05)',
      border:`1px solid ${isConnected ? dev.color+'44' : 'rgba(255,255,255,0.1)'}`,
      display:'flex', alignItems:'center', justifyContent:'center',
      boxShadow: isConnected ? `0 0 16px ${dev.color}44` : 'none',
      overflow:'hidden', transition:'all 0.2s',
    }}>
      <img src={dev.img} alt={dev.name} style={{ width:34, height:34, objectFit:'contain' }}
        onError={e => {
          e.target.style.display='none';
          e.target.parentNode.innerHTML=`<span style="font-size:0.68rem;font-weight:800;color:${dev.color}">${dev.name.slice(0,2).toUpperCase()}</span>`;
        }} />
    </div>

    {/* Info */}
    <div style={{ flex:1, minWidth:0 }}>
      <div style={{ fontSize:'0.92rem', fontWeight:700, color: isConnected ? '#fff' : '#c8dff0', marginBottom:3 }}>{dev.name}</div>
      <div style={{ fontSize:'0.72rem', color:'#3d6b8a', lineHeight:1.4 }}>{dev.desc}</div>
      {isConnected && (
        <div style={{ display:'flex', alignItems:'center', gap:6, marginTop:6 }}>
          <div style={{ width:7, height:7, borderRadius:'50%', background:'#34d399', boxShadow:'0 0 6px #34d399' }} />
          <span style={{ fontSize:'0.65rem', color:'#34d399', fontWeight:700 }}>Connected · Syncing data</span>
        </div>
      )}
    </div>

    {/* Button */}
    <button onClick={onAction} disabled={isSyncing} style={{
      flexShrink:0, padding:'0.5rem 1.15rem', borderRadius:20,
      border:`1px solid ${actionColor}55`,
      background:`${actionColor}18`,
      color: actionColor, fontWeight:700, fontSize:'0.74rem',
      cursor: isSyncing ? 'default' : 'pointer',
      transition:'all 0.2s', whiteSpace:'nowrap', letterSpacing:'0.04em',
      display:'flex', alignItems:'center', gap:'0.4rem',
    }}
      onMouseEnter={e=>{ if(!isSyncing) e.currentTarget.style.transform='scale(1.06)'; }}
      onMouseLeave={e=>{ e.currentTarget.style.transform='scale(1)'; }}
    >
      {isSyncing && (
        <span style={{ display:'inline-block', width:13, height:13, border:`2px solid ${actionColor}`, borderTopColor:'transparent', borderRadius:'50%', animation:'spin 0.7s linear infinite' }} />
      )}
      {isSyncing ? 'Connecting…' : actionLabel}
    </button>
  </div>
);

// ─── Sync Modal (fixed, centred) ──────────────────────────────────────────────
const SyncModal = ({ onClose }) => {
  const [tab, setTab]         = useState('my');
  const [devices, setDevices] = useState(INIT_DEVICES);
  const [syncing, setSyncing] = useState(null);

  const handleToggle = (id) => {
    const dev = devices.find(d => d.id === id);
    if (dev.connected) {
      setDevices(prev => prev.map(d => d.id===id ? {...d, connected:false} : d));
    } else {
      setSyncing(id);
      setTimeout(() => { setDevices(prev => prev.map(d => d.id===id ? {...d, connected:true} : d)); setSyncing(null); }, 1800);
    }
  };

  const handleAddNew = (newDev) => {
    if (devices.find(d => d.id===newDev.id)) return;
    setSyncing(newDev.id);
    setTimeout(() => { setDevices(prev => [...prev, {...newDev, connected:true}]); setSyncing(null); setTab('my'); }, 1800);
  };

  const connected = devices.filter(d => d.connected).length;

  const TabBtn = ({ k, label }) => (
    <button onClick={() => setTab(k)} style={{
      flex:1, padding:'0.65rem 0', fontWeight:700, fontSize:'0.82rem',
      border:'none', borderRadius:10, cursor:'pointer', letterSpacing:'0.04em',
      transition:'all 0.18s',
      background: tab===k ? 'linear-gradient(135deg,rgba(91,184,255,0.2),rgba(52,211,153,0.1))' : 'transparent',
      color: tab===k ? '#fff' : '#3d6b8a',
      borderBottom: tab===k ? '2px solid #5bb8ff' : '2px solid transparent',
    }}>{label}</button>
  );

  return (
    <>
      {/* Backdrop */}
      <div onClick={onClose} style={{
        position:'fixed', inset:0,
        background:'rgba(0,0,0,0.55)',
        backdropFilter:'blur(6px)',
        zIndex:9998,
      }} />

      {/* Modal — fixed, centred */}
      <div style={{
        position:'fixed',
        top:'50%', left:'50%',
        transform:'translate(-50%,-50%)',
        width: 'min(640px, 92vw)',
        maxHeight:'88vh',
        background:'linear-gradient(160deg,#0c1e30 0%,#0f2840 50%,#0c1e30 100%)',
        border:'1px solid rgba(91,184,255,0.22)', borderRadius:28,
        boxShadow:'0 40px 100px rgba(0,0,0,0.8), 0 0 0 1px rgba(91,184,255,0.06)',
        zIndex:9999, overflow:'hidden',
        display:'flex', flexDirection:'column',
        animation:'centrePopIn 0.28s cubic-bezier(0.34,1.56,0.64,1)',
      }}>
        {/* Accent line */}
        <div style={{ height:3, background:'linear-gradient(90deg,transparent,#34d399,#60a5fa,#34d399,transparent)', opacity:0.9, flexShrink:0 }} />

        {/* Header */}
        <div style={{
          display:'flex', alignItems:'center', justifyContent:'space-between',
          padding:'1.5rem 1.8rem 1.2rem',
          borderBottom:'1px solid rgba(91,184,255,0.1)',
          background:'rgba(52,211,153,0.03)', flexShrink:0,
        }}>
          <div style={{ display:'flex', alignItems:'center', gap:'1rem' }}>
            <div style={{
              width:48, height:48, borderRadius:15,
              background:'rgba(52,211,153,0.12)', border:'1px solid rgba(52,211,153,0.28)',
              display:'flex', alignItems:'center', justifyContent:'center',
              boxShadow:'0 0 16px rgba(52,211,153,0.25)', overflow:'hidden',
            }}>
              <img src="/fitness-tracker.png" alt="Sync"
                style={{ width:30, height:30, objectFit:'contain', filter:'drop-shadow(0 0 5px rgba(52,211,153,0.7))' }}
                onError={e=>e.target.style.display='none'} />
            </div>
            <div>
              <div style={{ fontWeight:800, fontSize:'1.15rem', color:'#fff', lineHeight:1.2 }}>Sync Devices</div>
              <div style={{ fontSize:'0.75rem', color:'#5a88a8', marginTop:3 }}>
                {connected > 0
                  ? <span style={{ color:'#34d399', fontWeight:600 }}>{connected} device{connected>1?'s':''} connected</span>
                  : <span style={{ color:'#5a88a8', fontWeight:600 }}>No devices connected</span>}
              </div>
            </div>
          </div>
          <button onClick={onClose} style={{
            background:'rgba(255,255,255,0.06)', border:'1px solid rgba(255,255,255,0.12)',
            borderRadius:'50%', width:36, height:36, color:'#5a88a8',
            fontSize:'0.9rem', cursor:'pointer',
            display:'flex', alignItems:'center', justifyContent:'center', transition:'all 0.15s',
          }}
            onMouseEnter={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.14)'; e.currentTarget.style.color='#fff'; }}
            onMouseLeave={e=>{ e.currentTarget.style.background='rgba(255,255,255,0.06)'; e.currentTarget.style.color='#5a88a8'; }}
          >✕</button>
        </div>

        {/* Tabs */}
        <div style={{
          display:'flex', gap:'0.3rem',
          padding:'0.85rem 1.4rem 0',
          borderBottom:'1px solid rgba(255,255,255,0.06)',
          background:'rgba(255,255,255,0.01)', flexShrink:0,
        }}>
          <TabBtn k="my"  label="My Devices" />
          <TabBtn k="new" label="+ Connect New Device" />
        </div>

        {/* Scrollable list */}
        <div className="sync-scroll" style={{ overflowY:'auto', padding:'1rem 1.4rem', flex:1 }}>

          {/* MY DEVICES */}
          {tab==='my' && (
            <div style={{ display:'flex', flexDirection:'column', gap:'0.6rem' }}>
              {devices.length===0 && (
                <div style={{ textAlign:'center', padding:'3rem', color:'#3d6b8a', fontSize:'0.82rem' }}>
                  No devices added yet. Switch to "Connect New Device".
                </div>
              )}
              {devices.map(dev => (
                <DeviceRow key={dev.id} dev={dev}
                  isConnected={dev.connected}
                  isSyncing={syncing===dev.id}
                  actionLabel={dev.connected ? 'Disconnect' : '+ Connect'}
                  actionColor={dev.connected ? '#f87171' : dev.color}
                  onAction={() => handleToggle(dev.id)}
                />
              ))}
            </div>
          )}

          {/* CONNECT NEW */}
          {tab==='new' && (
            <div style={{ display:'flex', flexDirection:'column', gap:'0.6rem' }}>
              <p style={{ fontSize:'0.75rem', color:'#3d6b8a', margin:'0 0 0.6rem 0.2rem' }}>
                Select a device below to pair it with HealUp
              </p>
              {NEW_DEVICES.map(dev => {
                const alreadyAdded = !!devices.find(d => d.id===dev.id);
                return (
                  <DeviceRow key={dev.id} dev={dev}
                    isConnected={alreadyAdded}
                    isSyncing={syncing===dev.id}
                    actionLabel={alreadyAdded ? '✓ Added' : '+ Add'}
                    actionColor={alreadyAdded ? '#34d399' : dev.color}
                    onAction={() => !alreadyAdded && handleAddNew(dev)}
                  />
                );
              })}
            </div>
          )}
        </div>

        {/* Footer */}
        <div style={{
          padding:'1rem 1.4rem 1.2rem',
          borderTop:'1px solid rgba(91,184,255,0.1)',
          background:'rgba(52,211,153,0.02)',
          display:'flex', alignItems:'center', justifyContent:'space-between', gap:'1rem',
          flexShrink:0,
        }}>
          <span style={{ fontSize:'0.72rem', color:'#3d6b8a' }}>🔒 Data is encrypted end-to-end</span>
          <button style={{
            padding:'0.6rem 1.5rem',
            background:'linear-gradient(135deg,rgba(52,211,153,0.22),rgba(96,165,250,0.14))',
            border:'1px solid rgba(52,211,153,0.35)', borderRadius:14,
            color:'#34d399', fontWeight:800, fontSize:'0.82rem',
            cursor:'pointer', transition:'all 0.18s', letterSpacing:'0.04em', whiteSpace:'nowrap',
          }}
            onMouseEnter={e=>{ e.currentTarget.style.background='rgba(52,211,153,0.32)'; e.currentTarget.style.transform='translateY(-1px)'; }}
            onMouseLeave={e=>{ e.currentTarget.style.background='linear-gradient(135deg,rgba(52,211,153,0.22),rgba(96,165,250,0.14))'; e.currentTarget.style.transform='translateY(0)'; }}
          >↻ Sync All Now</button>
        </div>
      </div>
    </>
  );
};

// ─── Layout ───────────────────────────────────────────────────────────────────
const Layout = ({ children, stats = { xp: 0, coins: 0 } }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [notifOpen, setNotifOpen] = useState(false);
  const [syncOpen,  setSyncOpen]  = useState(false);
  const [read, setRead]           = useState({});
  const notifRef = useRef(null);
  const unread   = NOTIFICATIONS.filter(n => !read[n.id]).length;

  useEffect(() => {
    const h = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) setNotifOpen(false);
    };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  const markAll       = () => setRead(Object.fromEntries(NOTIFICATIONS.map(n => [n.id, true])));
  const handleViewAll = () => { markAll(); setNotifOpen(false); navigate('/notifications'); };

  const menuItems = [
    { path:'/',              icon:'/dashboard.png',         label:'Dashboard' },
    { path:'/program',       icon:'/user.png',              label:'Program and Avatar customization' },
    { path:'/challenges',    icon:'/rpg-game.png',          label:'Challenges' },
    { path:'/goals',         icon:'/dart.png',              label:'Goals and Progress' },
    { path:'/activity-food', icon:'/healthy-food.png',      label:'Daily Health Log' },
    { path:'/notifications', icon:'/notification-bell.png', label:'Notifications and Report' },
    { path:'/chatbot',       icon:'/robot (1).png',         label:'Chatbot' },
  ];

  return (
    <div>
      <header className="topbar">
        <div className="topbar-left">
          <img src="/logo-transparent.png" alt="Logo" className="topbar-logo" />
          <span className="topbar-brand">HealUp!</span>
        </div>

        <div className="topbar-center">
          <button className="topbar-icon-btn" onClick={() => navigate('/chatbot')} title="AI Chatbot">
            <img src="/robot.png" alt="Chatbot" className="topbar-icon-img" />
          </button>

          {/* Sync — opens centred modal */}
          <button className="topbar-icon-btn" title="Sync Devices"
            onClick={() => { setSyncOpen(p => !p); setNotifOpen(false); }}
            style={{ position:'relative' }}>
            <img src="/fitness-tracker.png" alt="Sync" className="topbar-icon-img"
              style={syncOpen ? { filter:'drop-shadow(0 0 6px rgba(52,211,153,0.9))' } : {}} />
          </button>

          {/* Bell */}
          <div ref={notifRef} style={{ position:'relative' }}>
            <button className="topbar-icon-btn" title="Alerts"
              onClick={() => { setNotifOpen(p => !p); setSyncOpen(false); }}
              style={{ position:'relative' }}>
              <img src="/notification.png" alt="Alerts" className="topbar-icon-img"
                style={notifOpen ? { filter:'drop-shadow(0 0 6px rgba(91,184,255,0.9))' } : {}} />
              {unread > 0 && (
                <span style={{
                  position:'absolute', top:1, right:1, minWidth:17, height:17,
                  background:'linear-gradient(135deg,#ef4444,#dc2626)', borderRadius:20,
                  fontSize:'0.58rem', fontWeight:900, color:'#fff',
                  display:'flex', alignItems:'center', justifyContent:'center',
                  border:'2px solid #0b1a27', padding:'0 3px',
                  boxShadow:'0 0 8px rgba(239,68,68,0.7)', pointerEvents:'none',
                }}>{unread}</span>
              )}
            </button>

            {notifOpen && (
              <div style={{
                position:'absolute', top:'calc(100% + 14px)', right:'-160px', width:520,
                background:'linear-gradient(160deg,#0c1e30 0%,#0f2840 50%,#0c1e30 100%)',
                border:'1px solid rgba(91,184,255,0.22)', borderRadius:26,
                boxShadow:'0 32px 90px rgba(0,0,0,0.75)',
                zIndex:9999, overflow:'hidden',
                animation:'notifDropIn 0.25s cubic-bezier(0.34,1.56,0.64,1)',
              }}>
                <div style={{ height:3, background:'linear-gradient(90deg,transparent,#5bb8ff,#a78bfa,#5bb8ff,transparent)', opacity:0.85 }} />
                <div style={{
                  display:'flex', alignItems:'center', justifyContent:'space-between',
                  padding:'1.3rem 1.6rem 1.1rem',
                  borderBottom:'1px solid rgba(91,184,255,0.1)',
                  background:'rgba(91,184,255,0.03)',
                }}>
                  <div style={{ display:'flex', alignItems:'center', gap:'0.85rem' }}>
                    <div style={{
                      width:42, height:42, borderRadius:13,
                      background:'rgba(91,184,255,0.12)', border:'1px solid rgba(91,184,255,0.28)',
                      display:'flex', alignItems:'center', justifyContent:'center',
                      fontSize:'1.2rem', boxShadow:'0 0 14px rgba(91,184,255,0.22)',
                    }}>🔔</div>
                    <div>
                      <div style={{ fontWeight:800, fontSize:'1.05rem', color:'#fff', lineHeight:1.2 }}>Notifications</div>
                      <div style={{ fontSize:'0.72rem', color:'#5a88a8', marginTop:3 }}>
                        {unread > 0
                          ? <span style={{ color:'#f87171', fontWeight:600 }}>{unread} unread alerts</span>
                          : <span style={{ color:'#34d399', fontWeight:600 }}>All caught up ✓</span>}
                      </div>
                    </div>
                  </div>
                  <button onClick={markAll} style={{
                    background:'rgba(91,184,255,0.08)', border:'1px solid rgba(91,184,255,0.22)',
                    borderRadius:20, color:'#5bb8ff', fontSize:'0.73rem', fontWeight:700,
                    cursor:'pointer', padding:'6px 16px', transition:'all 0.15s',
                  }}
                    onMouseEnter={e=>e.currentTarget.style.background='rgba(91,184,255,0.2)'}
                    onMouseLeave={e=>e.currentTarget.style.background='rgba(91,184,255,0.08)'}
                  >Mark all read</button>
                </div>

                <div className="notif-scroll" style={{ maxHeight:460, overflowY:'auto', padding:'0.85rem 1rem' }}>
                  {NOTIFICATIONS.map((n, idx) => {
                    const s = NS[n.type]; const isRead = !!read[n.id];
                    return (
                      <div key={n.id} onClick={() => setRead(p=>({...p,[n.id]:true}))}
                        style={{
                          display:'flex', gap:'1rem', alignItems:'flex-start',
                          padding:'1rem 1.1rem', borderRadius:18,
                          background: isRead ? 'rgba(255,255,255,0.02)' : s.bg,
                          border:`1px solid ${isRead ? 'rgba(255,255,255,0.05)' : s.border}`,
                          marginBottom: idx<NOTIFICATIONS.length-1 ? '0.55rem' : 0,
                          cursor:'pointer', transition:'transform 0.18s', opacity: isRead ? 0.45 : 1,
                        }}
                        onMouseEnter={e=>{ if(!isRead) e.currentTarget.style.transform='translateX(4px)'; }}
                        onMouseLeave={e=>{ e.currentTarget.style.transform='translateX(0)'; }}
                      >
                        <div style={{
                          width:48, height:48, borderRadius:14, flexShrink:0,
                          background: isRead ? 'rgba(255,255,255,0.04)' : s.bg,
                          border:`1px solid ${isRead ? 'rgba(255,255,255,0.08)' : s.border}`,
                          display:'flex', alignItems:'center', justifyContent:'center', fontSize:'1.35rem',
                          boxShadow: isRead ? 'none' : `0 0 16px ${s.glow}44`,
                        }}>{n.icon}</div>
                        <div style={{ flex:1, minWidth:0 }}>
                          <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', gap:'0.4rem', marginBottom:5 }}>
                            <span style={{ fontSize:'0.9rem', fontWeight:700, color: isRead?'#4a7a9b':'#e2e8f0' }}>{n.title}</span>
                            {!isRead && <div style={{ width:10, height:10, borderRadius:'50%', flexShrink:0, background:s.dot, boxShadow:`0 0 8px ${s.glow}` }} />}
                          </div>
                          <div style={{ fontSize:'0.77rem', color: isRead?'#3d5c72':'#5a88a8', lineHeight:1.6, marginBottom:8 }}>{n.desc}</div>
                          <div style={{ display:'flex', alignItems:'center', gap:'0.55rem' }}>
                            <span style={{ fontSize:'0.64rem', fontWeight:700, padding:'3px 10px', borderRadius:20, letterSpacing:'0.05em', color:s.tag.color, background:s.tag.bg, border:`1px solid ${s.tag.border}` }}>{n.tag}</span>
                            <span style={{ fontSize:'0.65rem', color:'#2e5470' }}>{n.time}</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>

                <div style={{ padding:'1rem 1.1rem', borderTop:'1px solid rgba(91,184,255,0.1)', background:'rgba(91,184,255,0.02)' }}>
                  <button onClick={handleViewAll} style={{
                    width:'100%', padding:'0.88rem',
                    background:'linear-gradient(135deg,rgba(91,184,255,0.18),rgba(167,139,250,0.12))',
                    border:'1px solid rgba(91,184,255,0.3)', borderRadius:16,
                    color:'#fff', fontWeight:800, fontSize:'0.92rem',
                    cursor:'pointer', letterSpacing:'0.05em', transition:'all 0.18s',
                    display:'flex', alignItems:'center', justifyContent:'center', gap:'0.6rem',
                  }}
                    onMouseEnter={e=>{ e.currentTarget.style.background='linear-gradient(135deg,rgba(91,184,255,0.3),rgba(167,139,250,0.22))'; e.currentTarget.style.transform='translateY(-1px)'; }}
                    onMouseLeave={e=>{ e.currentTarget.style.background='linear-gradient(135deg,rgba(91,184,255,0.18),rgba(167,139,250,0.12))'; e.currentTarget.style.transform='translateY(0)'; }}
                  >
                    <span>📋</span> View All Notifications &amp; Reports <span style={{ opacity:0.7 }}>→</span>
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Right */}
        <div className="topbar-right">
          <div className="topbar-stat-chip xp-chip">
            <img src="/star.png" alt="XP" className="topbar-stat-icon-img" />
            <span className="topbar-stat-value">{stats.xp.toLocaleString()}</span>
            <span className="topbar-stat-label">XP</span>
          </div>
          <div className="topbar-stat-chip coins-chip">
            <img src="/profit.png" alt="Coins" className="topbar-stat-icon-img" />
            <span className="topbar-stat-value">{stats.coins.toLocaleString()}</span>
            <span className="topbar-stat-label">Coins</span>
          </div>
          <div className="topbar-avatar-chip">
            <div className="topbar-avatar-dot" />
            <span className="topbar-avatar-name">My Profile</span>
          </div>
        </div>
      </header>

      <div className="layout-container">
        <aside className="sidebar">
          <nav className="sidebar-nav">
            {menuItems.map(item => (
              <Link key={item.path} to={item.path}
                className={`sidebar-item ${location.pathname===item.path?'active':''}`}
                data-testid={`nav-${item.label.toLowerCase().replace(/\s+/g,'-')}`}>
                <img src={item.icon} alt={item.label} className="sidebar-icon-img" />
                <span className="sidebar-label">{item.label}</span>
              </Link>
            ))}
          </nav>
        </aside>
        <main className="main-content">{children}</main>
      </div>

      {/* Sync modal rendered at root level so it's truly centred */}
      {syncOpen && <SyncModal onClose={() => setSyncOpen(false)} />}

      <style>{SHARED_STYLES}</style>
    </div>
  );
};

export default Layout;
